import React from 'react';
import { Card, CardContent, Box, Stack, Typography, Grid, Chip } from '@mui/material';
import response from './response.json';

interface RoomData {
  name: string;
  PM2_5: number;
  CO2: number;
  humidity: number;
}

interface AirQualityData {
  overall: {
    PM2_5: number;
    CO2: number;
    humidity: number;
  };
  rooms: RoomData[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const airQualityData = response.data as AirQualityData;
  const metaData = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#303030' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FFFFFF' }}>
              Air Quality Overview
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#B0BEC5' }}>
              PM2.5: {airQualityData.overall.PM2_5} µg/m³
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#B0BEC5' }}>
              CO2: {airQualityData.overall.CO2} ppm
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#B0BEC5' }}>
              Humidity: {airQualityData.overall.humidity}%
            </Typography>
          </Box>

          <Grid container spacing={1}>
            {airQualityData.rooms.map((room) => (
              <Grid item xs={4} key={room.name}>
                <Box>
                  <Typography variant="caption" color="text.secondary" sx={{ color: '#B0BEC5', fontWeight: 500 }}>
                    {room.name}
                  </Typography>
                  <Stack direction="column" spacing={0.5}>
                    <Chip
                      label={`PM2.5: ${room.PM2_5}`}
                      sx={{ fontSize: '10px', bgcolor: metaData.accentColor, color: '#000' }}
                    />
                    <Chip
                      label={`CO2: ${room.CO2}`}
                      sx={{ fontSize: '10px', bgcolor: metaData.primaryColor, color: '#000' }}
                    />
                    <Chip
                      label={`Humidity: ${room.humidity}%`}
                      sx={{ fontSize: '10px', bgcolor: metaData.accentColor, color: '#000' }}
                    />
                  </Stack>
                </Box>
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
